import{_ as o}from"./chunks/v2-dashboard.BbrlQuFY.js";import{_ as t}from"./chunks/v2-mod-diff._z3eTIVk.js";import{_ as r,o as e,c as s,ag as i}from"./chunks/framework.CvgP6Fyv.js";const f=JSON.parse('{"title":"做房主 — 分享你的 Mod 配置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/host.md","filePath":"guide/host.md","lastUpdated":1777473251000}'),d={name:"guide/host.md"};function l(n,a,p,h,m,_){return e(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="做房主-—-分享你的-mod-配置" tabindex="-1">做房主 — 分享你的 Mod 配置 <a class="header-anchor" href="#做房主-—-分享你的-mod-配置" aria-label="Permalink to &quot;做房主 — 分享你的 Mod 配置&quot;">​</a></h1><p>作为房主，你负责维护和上传 Mod 配置，队友从你这里同步。</p><p><img src="'+o+'" alt="仪表盘"></p><h2 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h2><ol><li>在仪表盘的「创建分支」卡片中填入一个名称（比如用几个字描述一下这个分支有些啥），点击「<strong>创建</strong>」</li><li>像平时一样安装、调整 Mods，也可以使用内置的 <a href="/guide/mod-manager">Mod 管理器</a> 来管理</li><li>完成后点击「<strong>上传</strong>」</li></ol><p>上传前会自动弹出 <strong>Mod 差异预览</strong>，展示本次上传新增、更新、移除了哪些 Mod，确认后才会真正上传。</p><p><img src="'+t+'" alt="Mod 差异预览"></p><p>队友即可同步到你的最新 Mod 配置。</p><h2 id="启动游戏" tabindex="-1">启动游戏 <a class="header-anchor" href="#启动游戏" aria-label="Permalink to &quot;启动游戏&quot;">​</a></h2><p>仪表盘上有「<strong>启动游戏</strong>」按钮，可以一键启动 Steam 游戏。如果游戏不在 Steam 上，也可以在下拉菜单中设置自定义启动路径。</p><h2 id="冲突处理" tabindex="-1">冲突处理 <a class="header-anchor" href="#冲突处理" aria-label="Permalink to &quot;冲突处理&quot;">​</a></h2><p>如果上传时云端存在更新的内容（例如你在另一台电脑改动过），会弹窗让你选择：</p><ul><li><strong>使用本地版本</strong> — 以当前电脑的配置为准，覆盖云端</li><li><strong>使用云端版本</strong> — 放弃本地改动，拉取云端最新配置</li></ul>',13)])])}const M=r(d,[["render",l]]);export{f as __pageData,M as default};
